<template>
    <el-dialog :visible="showDialog" @open="open" @close="close" :title="title">
        <div class="row m-1" v-if="commercialTreatment">
            <span class="h4">
                Tipo de afectación: {{ commercialTreatment.is_amount ? 'Monto' : 'Porcentaje' }}
            </span>
        </div>
        <div class="d-flex flex-wrap justify-content-center">
            <div v-for="(data,idx) in tableData" :key="idx" class="m-1">
                <label for="desc">
                    {{data.name}}
                </label>
                <el-input
                class="w-100"
                v-model="data.amount"
                ></el-input>
            </div>
        </div>

        <span slot="footer" class="dialog-footer">
            <el-button @click="close">Cancelar</el-button>
            <el-button type="primary" @click="submit">Guardar</el-button>
        </span>
    </el-dialog>
</template>

<script>
export default {
    props: ["showDialog", "commercialTreatment"],
    data() {
        return {
            originalTitle: "Categoria x tratamiento comercial",
            title: "Categoria x tratamiento comercial",
            form: {},
            loading: false,
            resource: "commercial_treatment/categories",
            tableData: []
        };
    },
    methods: {
        async getTable() {
            const response = await this.$http.get(
                `${this.resource}/records/${this.commercialTreatment.id}`
            );
                if(response.status == 200){
                    this.tableData = response.data;
                }

        },
        async submit(){

        },
        async open() {
            this.title =
                this.originalTitle + "/" + this.commercialTreatment.description;
            await this.getTable();
        },
        async close() {
            this.$emit("update:showDialog", false);
        }
    }
};
</script>



